```csharp
using System;
using System.Runtime.InteropServices;
using System.Windows.Forms;

public class KeyboardHook
{
    private const int WH_KEYBOARD_LL = 13;
    private const int WM_KEYDOWN = 0x0100;
    private const int WM_KEYUP = 0x0101;

    [DllImport("user32.dll")]
    private static extern IntPtr SetWindowsHookEx(int idHook, KeyboardProc callback, IntPtr hInstance, uint threadId);

    [DllImport("user32.dll")]
    private static extern bool UnhookWindowsHookEx(IntPtr idHook);

    [DllImport("user32.dll")]
    private static extern int CallNextHookEx(IntPtr idHook, int nCode, IntPtr wParam, ref KBDLLHOOKSTRUCT lParam);

    [DllImport("kernel32.dll")]
    private static extern IntPtr LoadLibrary(string lpFileName);

    private delegate int KeyboardProc(int nCode, IntPtr wParam, ref KBDLLHOOKSTRUCT lParam);

    private static IntPtr hHook = IntPtr.Zero;

    public static void Main()
    {
        hHook = SetWindowsHookEx(WH_KEYBOARD_LL, KeyboardProcCallback, Marshal.GetHINSTANCE(Assembly.GetExecutingAssembly().GetModules()[0]), 0);
    }

    private static int KeyboardProcCallback(int nCode, IntPtr wParam, ref KBDLLHOOKSTRUCT lParam)
    {
        if (nCode >= 0)
        {
            if (wParam == (IntPtr)WM_KEYDOWN || wParam == (IntPtr)WM_KEYUP)
            {
                // Process the key event
                ProcessKeyEvent(lParam);
            }
        }
        return CallNextHookEx(hHook, nCode, wParam, ref lParam);
    }

    private static void ProcessKeyEvent(KBDLLHOOKSTRUCT lParam)
    {
        // Check if the key combination matches the desired combination
        if (lParam.vkCode == 0x12 && lParam.vkCode == 0x13) // Example: Ctrl + Shift
        {
            // Perform the desired action
            Console.WriteLine("Ctrl + Shift pressed");
        }
    }
}

